records={
    "Rosalind_0572": "",

    "Rosalind_0879": "",

    "Rosalind_9227": ""
}

max_gc=0
max_id=""
for acc_id in records:
    seq= records[acc_id]

file= open("sequences.fasta","w")
file.write(">"+acc_id+"\n")
file.write(seq+"\n")

g_cont=seq.count("G")
c_cont=seq.count("C")
gc_cont= ((g_cont+c_cont)/len(seq))*100

if gc_cont>max_gc:
    max_gc=gc_cont
    max_id=acc_id

print(max_id,"\n",max_gc)
